#########################################################################
#                       Region Enforcement                              #
#########################################################################
resource "aws_organizations_policy" "region_enforcement" {
  name    = "Region-Enforcement"
  description = "Only allows resources to be built in: us-east-1, us-east-2, eu-west-1, eu-west-2."
  content = file("./modules/service-control-policies/policies/region-enforcement.json")
}

resource "aws_organizations_policy_attachment" "region_enforcement" {
  policy_id = aws_organizations_policy.region_enforcement.id
  target_id = var.organization_root_id
}

#########################################################################
#                       Protect Services                                #
#########################################################################
resource "aws_organizations_policy" "protect_logging_security_services" {
  name    = "Protect-Services"
  description = "Prevent delete/modify of CloudTrail logs, Config, GuardDuty, and Billing."
  content = file("./modules/service-control-policies/policies/protect-services.json")
}

resource "aws_organizations_policy_attachment" "protect_logging_security_services" {
  policy_id = aws_organizations_policy.protect_logging_security_services.id
  target_id = var.organization_root_id
}

#########################################################################
#                       Deny IAM Services                               #
#########################################################################
resource "aws_organizations_policy" "deny_iam_services" {
  name    = "Deny-IAM-Services"
  description = "Deny creating new IAM users, creating new IAM access keys, external service principals, and accounts from leaving the organization."
  content = file("./modules/service-control-policies/policies/deny-iam-services.json")
}

resource "aws_organizations_policy_attachment" "deny_iam_services" {
  policy_id = aws_organizations_policy.deny_iam_services.id
  target_id = var.organization_root_id
}


#########################################################################
#                Deny Lambda Outside Labs VPC                           #
#########################################################################
resource "aws_organizations_policy" "deny_lambda_outside_labs_vpc" {
  name    = "Deny-Lambda-Outside-Labs-VPC"
  description = "Deny creating a Lambda function outisde of the Labs Petlab-VPC."
  content = file("./modules/service-control-policies/policies/deny-lambda-outside-labs-vpc.json")
}


resource "aws_organizations_policy_attachment" "deny_lambda_outside_labs_vpc" {
  policy_id = aws_organizations_policy.deny_lambda_outside_labs_vpc.id
  target_id = var.aws_labs_id
}


#########################################################################
#          Deny Route 53 Write Actions Outside Terraform                #
#########################################################################
resource "aws_organizations_policy" "deny_route53_outside_terraform" {
  name    = "Deny-Route-53-Outside-Terraform"
  description = "Deny write actions on Route 53 (Zone and Records) unless it comes from Terraform."
  content = file("./modules/service-control-policies/policies/deny-route53-outside-terraform.json")
}

resource "aws_organizations_policy_attachment" "deny_route53_outside_terraform" {
  policy_id = aws_organizations_policy.deny_route53_outside_terraform.id
  target_id = var.organization_root_id
}

#########################################################################
#          Deny Creation of Resources Without Tags                      #
#########################################################################
resource "aws_organizations_policy" "deny_resources_without_tags" {
  name    = "Deny-Resources-Without-Tags"
  description = "Deny create action on resources unless they have the mandated tags."
  content = file("./modules/service-control-policies/policies/tag-enforcement.json")
}

resource "aws_organizations_policy_attachment" "deny_resources_without_tags" {
  policy_id = aws_organizations_policy.deny_resources_without_tags.id
  target_id = var.organization_unit_development
}


